fn process_items(data: &Vec<i32>) {
    println!("--- Inside function ---\n");
    for item in data.iter() {
        println!("Found value: {}", item);
    }
    println!("--- Finished processing items ---\n");
}

fn main() {
    let numbers = vec![10, 20, 30, 40];

    // The function looks at the data without taking it away
    process_items(&numbers);

    // We can still use 'numbers' here because we only let the function borrow it
    println!("--- Back in main ---\n");
    for i in &numbers[1..2] { 
        println!("Successfully accessed value: {}", i);
    }
}

fn process_data(list1: &Vec<i32>, list2: &Vec<String>) {
    println!("Processing data...");
    // We can use both lists here because we only borrowed them.
    let sum: i32 = list1.iter().sum();
    for item in list2.iter() {
        println!("Read item: {}", item);
    }
    println!("Finished processing.");
