fn main() {
    // 1. Create the data we want to keep ownership of.
    let numbers = vec![10, 20, 30];
    let names = vec![String::from("Alice"), String::from("Bob")];

    println!("--- Before calling process_data ---");
    // We can still use 'numbers' and 'names' here because we only borrowed them.
    println!("Main program: Numbers length is {}", numbers.len());
    println!("Main program: Names length is {}", names.len());

    // 2. Call the function, passing references (&) to keep ownership.
    process_data(&numbers, &names);

    println!("\n--- After calling process_data ---");
    // We can still use 'numbers' and 'names' here because they were only borrowed (read).
    println!("Main program: Numbers length is {}", numbers.len());
    println!("Main program: Names length is {}", names.len());
}

fn main() {
    let mut numbers = vec![10, 20, 30];

    // First time: We are reading the data (a borrow)
    println!("The first number is: {}", &numbers[0]);

    // Second time: We are also just reading it again. This is fine.
    let second_number = &numbers[1];
    println!("The second number is: {}", second_number);

    // If we tried to write here, Rust would enforce rules, but for now, 
    // just knowing that reading multiple times works is key.
}

fn process_user_list(users: &Vec<User>) -> usize {
    let mut count = 0;
    for user in users {
        if user.age >= 18 {
            count += 1;
        }
    }
    count
}

struct User {
    name: String,
    age: u32,
}

fn main() {
    let all_users = vec![
        User { name: String::from("Alice"), age: 25 },
        User { name: String::from("Bob"), age: 16 },
        User { name: String::from("Charlie"), age: 30 },
    ];

    let eligible_count = process_user_list(&all_users);
    println!("Found {} users who are over 18.", eligible_count);
}

fn process_data(items: &Vec<i32>) {
    println!("--- Starting data processing ---");
    for i in 0..items.len() {
        // We can read the value using indexing, which borrows it temporarily.
        let item = items[i];
        println!("Read item: {}", item);
    }
    println!("--- Finished data processing ---");
}

fn main() {
    // Create the original list that we need to keep at the end.
    let numbers = vec![10, 20, 30];
    println!("Original list created: {:?}", numbers);

    // We pass a reference (&) to the function. This lets it read the data without moving it.
    process_data(&numbers);

    // Because we only borrowed the data, 'numbers' is still here and usable.
    println!("Original list is still available after calling the function: {:?}", numbers);
}
